record.field:
for rec in records:
    values = {}
    if not rec.x_name and rec.id:
        values['x_name'] = 'MCEP-INT-%05d' % rec.id
    if rec.id and not rec.x_document_reference:
        values['x_document_reference'] = 'MCEP-HR-F-0002-%05d' % rec.id
    if not rec.x_interviewer_user_id:
        values['x_interviewer_user_id'] = env.user.id
    if not rec.x_interview_datetime:
        values['x_interview_datetime'] = datetime.datetime.now()
    if not rec.x_document_state:
        values['x_document_state'] = 'draft'
    if rec.x_ready_for_pdf:
        values['x_ready_for_pdf'] = False
    if rec.x_applicant_id:
        applicant = rec.x_applicant_id
        if applicant.partner_name or applicant.name or applicant.display_name:
            values['x_full_name_snapshot'] = applicant.partner_name or applicant.name or applicant.display_name
        if applicant.x_gender:
            values['x_gender_snapshot'] = applicant.x_gender
        if applicant.x_national_id:
            values['x_national_id_snapshot'] = applicant.x_national_id
        if applicant.job_id and applicant.job_id.name:
            values['x_position_applied_snapshot'] = applicant.job_id.with_context(lang='ar_001').name or applicant.job_id.name
        employee_number = getattr(applicant, 'x_employee_number', False) or getattr(applicant, 'employee_number', False)
        if employee_number:
            values['x_employee_number_snapshot'] = employee_number
    if values:
        rec.sudo().write(values)

    if rec.x_line_ids:
        continue

for rec in records:
    values = {}
    if rec.x_question_id:
        translated_ar = rec.x_question_id.x_label_ar or rec.x_question_id.with_context(lang='ar_001').x_name or rec.x_question_id.x_name
        translated_en = rec.x_question_id.x_label_en or rec.x_question_id.with_context(lang='en_US').x_name or rec.x_question_id.x_name
        if rec.x_question_label_ar != translated_ar:
            values['x_question_label_ar'] = translated_ar
        if rec.x_question_label_en != translated_en:
            values['x_question_label_en'] = translated_en
        default_max = rec.x_question_id.x_default_max_score or 5
        if rec.x_max_score != default_max:
            values['x_max_score'] = default_max

    actual_score = rec.x_actual_score
    if actual_score not in (False, None) and (actual_score < 1 or actual_score > 5):
        raise Warning('Interview question score must be between 1 and 5.')

    if values:
        rec.sudo().write(values)

    interview = rec.x_interview_id
    total_score = 0
    max_total = 0
    ready_for_pdf = True
    for line in interview.x_line_ids:
        line_score = line.x_actual_score
        if line_score in (False, None):
            ready_for_pdf = False
            line_score = 0
        elif line_score < 1 or line_score > 5:
            raise Warning('Interview question score must be between 1 and 5.')
        total_score += line_score
        max_total += (line.x_max_score or 0)
    percent = round((float(total_score) / float(max_total)) * 100.0, 2) if max_total else 0.0
    if percent >= 90.0:
        final_grade = 'excellent'
    elif percent >= 80.0:
        final_grade = 'very_good'
    elif percent >= 70.0:
        final_grade = 'good'
    elif percent >= 50.0:
        final_grade = 'acceptable'
    else:
        final_grade = 'not_acceptable'

    if percent < 25.0:
        stars = '0'
    elif percent < 40.0:
        stars = '1'
    elif percent < 55.0:
        stars = '2'
    elif percent < 70.0:
        stars = '3'
    elif percent < 85.0:
        stars = '4'
    else:
        stars = '5'

    interview.sudo().write({
        'x_total_score': total_score,
        'x_max_score': max_total,
        'x_percent_score': percent,
        'x_final_grade': final_grade,
        'x_visual_star_rating': stars,
        'x_ready_for_pdf': bool(ready_for_pdf and interview.x_line_ids),
    })
    applicant = interview.x_applicant_id
    if applicant:
        interviews = applicant.x_mcep_interview_ids.filtered(lambda r: r.x_max_score)
        avg_percent = 0.0
        if interviews:
            avg_percent = sum(interviews.mapped('x_percent_score')) / float(len(interviews))
        if avg_percent < 25.0:
            applicant_stars = '0'
        elif avg_percent < 50.0:
            applicant_stars = '1'
        elif avg_percent < 75.0:
            applicant_stars = '2'
        else:
            applicant_stars = '3'
        applicant.sudo().write({'priority': applicant_stars})

