for rec in records:
    if rec.x_signed_attachment_id:
        rec.sudo().write({
            'x_document_state': 'signed',
            'x_signed_on': datetime.datetime.now(),
        })
        rec.message_post(body='Signed interview PDF linked to the interview record.')
        if rec.x_applicant_id:
            rec.x_applicant_id.message_post(body='Signed interview PDF linked to applicant Files and interview record marked as signed.')
